\begin{align} &| \mathbf{a} | = | k (\mathbf{b} \times \mathbf{c} ) | \\ &\text{Substitute $| \mathbf{a} | = 1$ to get} \\ &1 = | k (\mathbf{b} \times \mathbf{c} ) | = |k||\mathbf{b} \times \mathbf{c}| \\ &\text{Note that the angle between} \mathbf{b} \text{and} \mathbf{c} \text{is } \pi/4 \text{ so } \\ &1 = | k | \sqrt{||\mathbf{b}||^2 - (\cos(\pi/4))^2||\mathbf{b}||^2} \\ &1 = | k | \sqrt{||\mathbf{b}||^2 - (1/√2)^2||\mathbf{b}||^2} \\ &1 = | k | \sqrt{||\mathbf{b}||^2(1 - 1/2)} \\ &1 = | k | ||\mathbf{b}|| \sqrt{1/2} \\ &1 = |k| ||b|| \frac{1}{\sqrt{2}} \\ &1 = | k | \frac{\sqrt{2}}{2} \\ &\text{Since this is a unit vector the magnitude of the magnitude of the magnitude must equal 1 so} \\ &| k | \frac{\sqrt{2}}{2} = 1 \\ &| k | = √{2} \\ &\boxed{k = -√2,√2} \end{align}
